interface ErrorReopenRules {
  /**
   * Must be one of the following:
   * - `n_additional_occurrences` - Indicates that the Error should be reopened after n more occurrences. In this case, the `occurrence_threshold` field indicates the number of total occurrences at which the Error should be reopened, and the `additional_occurrences` field indicates the number of additional occurrences that were allowed before reopening.
   * - `n_occurrences_in_m_hours` - Indicates that the Error should be reopened after n occurrences over some configurable number of hours. In this case, the `occurrences` and `hours` fields will both be present.
   * - `occurs_after` - Indicates that the error should be reopened if there are any occurrences after the specified time period. The `seconds` field contains the number of seconds that the Error has been snoozed for. In this case, the `seconds` and `reopen_after` fields will both be present.
   * - `n_additional_users` - Reopen the error after `n` more users are affected. In this case, the `additional_users` field must be provided.
   *
   * @type {string}
   * @memberof ErrorReopenRules
   */
  reopen_if: ErrorReopenRulesReopenIfEnum;
  /**
   * for `n_additional_users` reopen rules, the number of additional users to be affected by an Error before the Error is automatically reopened. Value cannot exceed 100,000.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  additional_users?: number;
  /**
   * for `occurs_after` reopen rules, this field indicates the time after which the Error should be reopened if there is an additional occurrence.
   * @type {string}
   * @memberof ErrorReopenRules
   */
  reopen_after?: string;
  /**
   * for `occurs_after` reopen rules, the number of seconds that the Error was set to snooze for.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  seconds?: number;
  /**
   * for `n_occurrences_in_m_hours` reopen rules, the number of occurrences to allow in the number of hours indicated by the `hours` field, before the Error is automatically reopened.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  occurrences?: number;
  /**
   * for `n_occurrences_in_m_hours` reopen rules, the number of hours.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  hours?: number;
  /**
   * for `n_additional_occurrences` reopen rules, the number of total occurrences at which the Error should be reopened.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  occurrence_threshold?: number;
  /**
   * for `n_additional_occurrences` reopen rules, the number of additional occurrences allowed before reopening.
   * @type {number}
   * @memberof ErrorReopenRules
   */
  additional_occurrences?: number;
}

