/**
 *
 * @export
 * @interface Integration
 */
interface Integration {
  /**
   * The key to uniquely identify the integration service.
   * @type {string}
   * @memberof Integration
   */
  key?: string;
  /**
   * The name of the integration service.
   * @type {string}
   * @memberof Integration
   */
  name?: string;
  /**
   * The URL of the integration service.
   * @type {string}
   * @memberof Integration
   */
  url?: string;
  /**
   * The type of the integration service.
   * - `issue-tracker` - An issue tracker integration. Used for creating and linking issues to Bugsnag errors.
   * - `team-notification` - A team communication tool integration. Used for alerting engineering teams when errors are reported to Bugsnag.
   * - `on-call` - An on call integration. Used for alerting ops teams when errors are reported to Bugsnag.
   * - `data-forwarding` - A data forwarding integration. Used for forwarding detailed error data when errors are reported to Bugsnag.
   *
   * @type {string}
   * @memberof Integration
   */
  type?: IntegrationTypeEnum;
  /**
   * Whether the integration supports two-way sync.
   * @type {boolean}
   * @memberof Integration
   */
  two_way_sync?: boolean;
  /**
   * A brief explanation of what the integration does.
   * @type {string}
   * @memberof Integration
   */
  description?: string;
  /**
   *
   * @type {IntegrationActions}
   * @memberof Integration
   */
  actions?: IntegrationActions;
  /**
   * The fields required to configure the integration.
   * @type {Array<IntegrationField>}
   * @memberof Integration
   */
  fields?: Array<IntegrationField>;
  /**
   * A URL containing an icon representing the service.
   * @type {string}
   * @memberof Integration
   */
  icon_url?: string;
  /**
   * A noun representing the entity that this integration can create (for issue-tracker type integrations only).
   * @type {string}
   * @memberof Integration
   */
  created_entity_name?: string;
  /**
   * Automation settings (for `issue-tracker` integrations only).
   * @type {Array<IntegrationAutomation>}
   * @memberof Integration
   */
  issue_automation_options?: Array<IntegrationAutomation>;
}

/**
 * @export
 */
const IntegrationTypeEnum = {
  IssueTracker: "issue-tracker",
  TeamNotification: "team-notification",
  OnCall: "on-call",
  DataForwarding: "data-forwarding",
} as const;

type IntegrationTypeEnum =
  (typeof IntegrationTypeEnum)[keyof typeof IntegrationTypeEnum];

